// Korean V2 Unit 18, 먹는 것을 좋아해요
// Level: B1.2

const UNIT_18 =
{n:18,lang:"ko",srcLang:"en",track:"v2",title:"먹는 것을 좋아해요",sub:"Nominalization & Modifiers",icon:"🍽️",level:"B1.2",color:"#7B5EE8",lessons:[

// ── L1: ★ -기 명사화 HARVEST (21 steps) ──
{id:"kou18l1",title:"★ -기 명사화",icon:"🌾",xp:26,board:true,steps:[
{type:"intro",title:"Harvesting -기 Nominalization",desc:"You've been seeing -기 since Unit 10.\n\n요리하기가 좋아요.\n→ Cooking is nice.\n\nTurn verbs into nouns with -기.",goals:["Master -기 nominalization","Use -기 with common patterns","Distinguish -기 from -는 것","Express activities as nouns"]},
{type:"teach",nl:"요리하다",en:"to cook",pos:"verb",gender:null,funFact:"To cook. One of the most useful 하다 verbs. 요리 (cooking) + 하다. Related: 요리사 (chef), 요리법 (recipe), 요리 프로그램 (cooking show).",phonetic:"yo-ri-ha-da",example:"A: 오늘 저녁 뭐 먹을까요?\nB: 집에서 요리할까요? 재료가 많아요.\nA: 좋아요! 뭐 요리할 거예요?\nB: 김치찌개를 요리해 볼게요.\nA: 요리하기 전에 손 씻으세요.",exampleEn:"A: What shall we eat tonight?\nB: Shall we cook at home? We have lots of ingredients.\nA: Great! What will you cook?\nB: I'll try making kimchi stew.\nA: Wash your hands before cooking.",note:"요리 (cooking) + 하다 (to do).\n요리하다 → 요리해요.\nOne of the most useful 하다 verbs.",kind:"word"},
{type:"teach",nl:"양념",en:"seasoning, sauce",pos:"noun",gender:null,funFact:"Seasoning. Covers sauces, marinades, spice mixes. 양념치킨 (seasoned fried chicken) is a famous Korean dish using dense 양념 glazes.",phonetic:"yang-nyeom",example:"A: 이 불고기 양념이 뭐예요?\nB: 간장이랑 설탕이랑 마늘이에요.\nA: 양념 맛이 정말 좋아요!\nB: 감사해요. 양념을 직접 만들었어요.\nA: 레시피를 알려 주세요!",exampleEn:"A: What is the seasoning for this bulgogi?\nB: It is soy sauce, sugar, and garlic.\nA: The seasoning flavor is really great!\nB: Thank you. I made the seasoning myself.\nA: Please share the recipe!",note:"Covers sauces, marinades, spice mixes.\n양념치킨 = seasoned fried chicken.\n고추장 양념 = gochujang sauce.",kind:"noun"},
{type:"tip",title:"-기: Making Verbs into Nouns",text:"Verb stem + -기 = noun form\n\n먹다 → 먹기 (eating)\n가다 → 가기 (going)\n요리하다 → 요리하기 (cooking)\n\nCommon patterns:\n-기 좋다 = good for doing\n-기 싫다 = hate doing\n-기 쉽다 = easy to do\n-기 어렵다 = hard to do\n-기로 하다 = decide to (U12!)",deepDive:"-기 vs -는 것:\n\nBoth turn verbs into nouns.\n\n-기: more abstract, fixed expressions\n요리하기 쉬워요 = Cooking is easy.\n\n-는 것: more concrete, specific\n요리하는 것을 좋아해요 = I like the act of cooking.\n\nMany patterns ONLY use -기:\n-기 시작하다 (start doing)\n-기 전에 (before doing)\n-기로 하다 (decide to)\n-기 위해서 (in order to)"},
{type:"mc",q:"한국어 배우기가 재미있어요 means:",opts:["Learning Korean is fun","I learned Korean","Korean learns me","I want to learn Korean"],ans:"Learning Korean is fun",hint:"-기 turns 배우다 into the noun 배우기. It is the subject here."},
{type:"fb",s:"한국 음식 만들{1} 어려워요?\n(Is making Korean food difficult?)",a:"기가",opts:["기가","기를","기에","기로"],hint:"The nominalized verb is the sentence subject. Which particle marks subjects?"},
{type:"mc",q:"Which pattern ONLY uses -기 (not -는 것)?",opts:["-기를 좋아하다 (like doing)","-기 전에 (before doing)","Both accept either","Neither uses -기"],ans:"-기 전에 (before doing)",hint:"Some grammar patterns are fixed with one specific nominalizer and cannot swap to the other."},
{type:"fb",s:"먹{1} 전에 손을 씻어야 해요.\n(Before eating, you must wash your hands.)",a:"기",opts:["기","는 것","을","어서"],hint:"The pattern 'before doing' uses a fixed nominalization form attached to the stem."},
{type:"mc",q:"운동하기 시작했어요 means:",opts:["I want to exercise","I'm exercising","I started exercising","Exercise started me"],ans:"I started exercising",hint:"시작하다 = to start. The past tense -했어요 tells you the starting already happened."},
{type:"teach",nl:"-기 위해서",en:"in order to (formal)",pos:"part",gender:null,funFact:"'In order to' (formal). Used for formal/written contexts. 건강을 지키기 위해서 운동해요 (I exercise in order to maintain health). Contrast informal -(으)려고.",phonetic:"-gi wi-hae-seo",example:"A: 왜 매일 운동해요?\nB: 건강해지기 위해서 운동해요.\nA: 한국어도 열심히 공부하죠?\nB: 네, 한국에서 일하기 위해서요.\nA: 목표가 있으면 좋겠어요.",exampleEn:"A: Why do you exercise every day?\nB: I exercise in order to get healthy.\nA: You study Korean hard too, right?\nB: Yes, in order to work in Korea.\nA: It is nice to have goals.",note:"Verb stem + -기 위해서.\nMore formal than -(으)려고.\n건강을 위해서 = for health.",kind:"grammar"},
{type:"fb",s:"건강{1} 위해서 운동해요.\n(I exercise for the sake of health.)",a:"을",opts:["을","기","에","는"],hint:"건강 is a noun here, not a verb. Nouns take an object particle before 위해서."},
{type:"mc",q:"-기 쉽다 vs -기 어렵다:",opts:["Before doing vs after doing","Start to do vs stop doing","Like doing vs hate doing","Easy to do vs hard to do"],ans:"Easy to do vs hard to do",hint:"쉽다 and 어렵다 sit at opposite ends of the difficulty scale. Both combine with -기."},
{type:"fb",s:"양념 만들{1} 어렵지만 재미있어요.\n(Making seasoning is hard but fun.)",a:"기가",opts:["기가","기를","기에","기로"],hint:"Making seasoning is the subject. Nominalization + which particle marks subjects?"},
{type:"drag_fill",s:"한국어 읽{1} 쉬운데, 쓰{2} 어려워요.\n(Reading Korean is easy, but writing is hard.)",blanks:{"1":"기는","2":"기가"},pool:["기는","기가","기를","기에","는 것"],hint:"Reading is contrasted (topic marker 는), writing is the new subject (subject marker 가)."},
{type:"match",pairs:[{nl:"-기 전에",en:"before doing"},{nl:"-기 시작하다",en:"start doing"},{nl:"-기 쉽다",en:"easy to do"},{nl:"-기 어렵다",en:"hard to do"}]},
{type:"fb",s:"요리하{1} 좋아해요. 매일 요리해요.\n(I like cooking. I cook every day.)",a:"기를",opts:["기를","기가","기에","는 것"],hint:"Cooking is the thing you like. 좋아하다 takes an object. Which particle marks objects?"},
{type:"mc",q:"건강을 위해서 요리하기로 했어요 combines which patterns?",opts:["위해서 (for the sake of) + -기로 하다 (decided to)","Only -기 위해서","Only -기로 하다","Neither pattern"],ans:"위해서 (for the sake of) + -기로 하다 (decided to)",hint:"Two different purpose/decision patterns appear in this single sentence."},
{type:"fb",s:"요리하{1} 위해서 양념을 샀어요.\n(I bought seasoning in order to cook.)",a:"기",opts:["기","는","은","을"],hint:"In order to cook. The purpose pattern attaches which form to the verb stem?"},
{type:"drag_fill",s:"매운 음식 먹{1} 싫은데, 건강을 {2} 조금씩 먹{3} 시작했어요.\n(I hate eating spicy food, but for my health I started eating little by little.)",blanks:{"1":"기가","2":"위해서","3":"기"},pool:["기가","위해서","기","기를","위해","기로"],hint:"Three -기 patterns: hate doing (-기가 싫다), for the sake of (위해서), start doing (-기 시작하다)."},
{type:"mc",q:"살기 좋은 도시 means:",opts:["A living city","A city that's good to live in","A city that lives well","I like living in the city"],ans:"A city that's good to live in",hint:"살기 = living (nominalized). 좋은 = … (modifier). Together they describe the …."},

{type:"fb",s:"한국에서는 {1} 문화가 중요해요.\n(In Korea, eating culture is important.)",a:["음식"],opts:["음식","먹기","먹는","먹을"],hint:"The compound noun combining 'food' and 'culture' is the answer."},
{type:"mc",q:"매운 음식을 잘 먹는 편이에요.\n(I tend to eat spicy food well.)",opts:["-게 되다","-고 있다","-는 편이다","-기로 하다"],ans:"-는 편이다",hint:"Describe eating tendencies as a general lean rather than an absolute statement."},
{type:"drag_fill",s:"한국 음식 중에서 비빔밥이 {1} 유명하고 김치찌개가 {2} 인기가 있어요.\n(Among Korean food, bibimbap is the most famous and kimchi stew is also popular.)",blanks:{"1":"제일","2":"제일"},pool:["제일","제일","더","더","가장","가장"],hint:"Superlative 제일/가장 used for ranking Korean foods."},
{type:"match",pairs:[{nl:"비빔밥",en:"mixed rice bowl"},{nl:"김치찌개",en:"kimchi stew"},{nl:"불고기",en:"grilled marinated beef"},{nl:"떡볶이",en:"spicy rice cakes"}]},
{type:"mc",q:"한국 사람들은 밥을 같이 먹으면서 이야기하는 것을 좋아해요.\n(Korean people like talking while eating together.)",opts:["-는데 + -기","-고 + -기","-아/어서 + -는 것","-(으)면서 + -는 것"],ans:"-(으)면서 + -는 것",hint:"Two grammar forms: doing two things at once, and turning a verb into a noun."},
{type:"fb",s:"한국 음식을 {1} 위해서 요리 수업을 듣고 있어요.\n(I am taking cooking classes in order to learn Korean food.)",a:["배우기"],opts:["배우기","배우는","배울","배운"],hint:"State the purpose of an activity using the purpose nominalizer."},
]},

// ── L2: 음식 어휘 확장 (21 steps) ──
{id:"kou18l2",title:"음식 어휘 확장",icon:"🍲",xp:22,board:true,steps:[
{type:"intro",title:"Korean Food Deep Dive",desc:"Beyond 김치 and 비빔밥.\n\nKorea's rich food culture\ndeserves a deeper look.",goals:["Learn 8+ Korean dishes","Understand Korean food categories","Talk about food preferences","Use food vocabulary with -기 patterns"]},
{type:"teach",nl:"찌개",en:"stew (thick, shared)",pos:"noun",gender:null,funFact:"Stew. Korean thick stew served boiling-hot at the table. Types: 김치찌개 (kimchi), 된장찌개 (soybean paste), 부대찌개 (army stew).",phonetic:"jji-gae",example:"A: 오늘 저녁 뭐 먹을까요?\nB: 찌개 어때요? 날씨가 추워요.\nA: 좋아요! 김치찌개 좋아해요.\nB: 된장찌개도 맛있어요.\nA: 그러면 된장찌개 만들어요!",exampleEn:"A: What shall we eat tonight?\nB: How about stew? The weather is cold.\nA: Great! I like kimchi stew.\nB: Soybean paste stew is also tasty.\nA: Then let us make soybean paste stew!",note:"Korean thick stew served boiling.\n김치찌개 = kimchi stew.\n된장찌개 = soybean paste stew.\nShared communal dish.",kind:"noun",deepDive:"찌개 vs 국 vs 탕:\n\n국: thin soup, individual serving\n찌개: thick stew, shared from center\n탕: hearty soup, often meat-based\n\n된장국 = thin soybean soup\n된장찌개 = thick soybean stew\n삼계탕 = ginseng chicken soup"},
{type:"teach",nl:"반찬",en:"side dishes",pos:"noun",gender:null,example:"A: 반찬이 뭐 있어요?\nB: 김치하고 나물이 있어요.",exampleEn:"A: What side dishes are there?\nB: Kimchi and vegetables.",funFact:"Sino-Korean compound: 반(accompany/伴) + 찬(dish/饌)",phonetic:"ban-chan",note:"COMPOUND: 반(accompany/伴) + 찬(dish/饌).\nAccompany-dish = side dishes.\nKorean meals always include many 반찬.",kind:"noun"},
{type:"teach",nl:"삼겹살",en:"pork belly (grilled)",pos:"noun",gender:null,example:"A: 저녁에 뭐 먹을까요?\nB: 삼겹살 먹어요!",exampleEn:"A: What should we eat for dinner?\nB: Let's have pork belly!",funFact:"Sino-Korean compound: 삼(three/三) + 겹(layers) + 살(meat)",phonetic:"sam-gyeop-sal",note:"COMPOUND: 삼(three/三) + 겹(layers) + 살(meat).\nThree-layer-meat = pork belly.\nKorea's most popular grilled meat.",kind:"noun"},
{type:"teach",nl:"떡볶이",en:"spicy rice cakes",pos:"noun",gender:null,funFact:"Spicy rice cakes. Korea's most popular street food. Found at every market and convenience store.",phonetic:"tteok-bokk-i",example:"A: 분식집에서 뭐 먹을까요?\nB: 떡볶이 먹고 싶어요!\nA: 떡볶이가 매워요?\nB: 좀 매운데 정말 맛있어요.\nA: 저도 한번 먹어 볼게요.",exampleEn:"A: What shall we eat at the snack shop?\nB: I want to eat spicy rice cakes!\nA: Are spicy rice cakes spicy?\nB: A little spicy but really delicious.\nA: I will try them too.",note:"떡(rice cake) + 볶이(stir-fried).\nKorea's most famous street food.\nSweet and spicy sauce.",kind:"noun"},
{type:"teach",nl:"냉면",en:"cold noodles",pos:"noun",gender:null,example:"A: 여름에 뭐 먹어요?\nB: 냉면을 자주 먹어요.",exampleEn:"A: What do you eat in summer?\nB: I often eat cold noodles.",funFact:"Sino-Korean compound: 냉(cold/冷) + 면(noodles/麵)",phonetic:"naeng-myeon",note:"COMPOUND: 냉(cold/冷) + 면(noodles/麵).\nCold-noodles. Summer favorite.\n물냉면 = in cold broth.\n비빔냉면 = mixed with spicy sauce.",kind:"noun"},
{type:"teach",nl:"삼계탕",en:"ginseng chicken soup",pos:"noun",gender:null,example:"A: 더운데 뭐 먹을까요?\nB: 삼계탕 어때요?",exampleEn:"A: It is hot. What should we eat?\nB: How about ginseng chicken soup?",funFact:"Sino-Korean compound: 삼(ginseng/蔘) + 계(chicken/鷄) + 탕(soup/湯)",phonetic:"sam-gye-tang",note:"COMPOUND: 삼(ginseng/蔘) + 계(chicken/鷄) + 탕(soup/湯).\nEaten on hottest days (복날) for stamina.",kind:"noun"},
{type:"teach",nl:"맛집",en:"famous restaurant",pos:"noun",gender:null,funFact:"Taste-house = a place known for good food.",phonetic:"mat-jip",example:"A: 이번 주말에 맛집에 갈까요?\nB: 좋아요! 어디가 맛있대요?\nA: 친구가 홍대 근처 맛집을 추천했어요.\nB: 예약해야 해요?\nA: 네, 줄이 길대요. 미리 예약하세요.",exampleEn:"A: Shall we go to a famous restaurant this weekend?\nB: Sure! Where do they say is good?\nA: A friend recommended a place near Hongdae.\nB: Do we need a reservation?\nA: Yes, the line is long they say. Please reserve in advance.",note:"맛(taste) + 집(house/restaurant).\nTaste-house = a place known for good food.\nKoreans love hunting for 맛집.",kind:"noun"},
{type:"teach",nl:"배달",en:"delivery",pos:"noun",gender:null,example:"A: 요리하기 싫어요.\nB: 그럼 배달 시켜요.",exampleEn:"A: I do not want to cook.\nB: Then let's order delivery.",funFact:"Sino-Korean compound: 배(distribute/配) + 달(reach/達)",phonetic:"bae-dal",note:"COMPOUND: 배(distribute/配) + 달(reach/達).\nDistribute-reach = delivery.\n배달 음식 = delivery food.",kind:"noun",deepDive:"Korea's delivery culture:\n\nKorea has one of the world's most advanced\nfood delivery systems.\n\n배달의민족: #1 delivery app\n요기요: #2 delivery app\n\nYou can get ANYTHING delivered:\nChicken, pizza, 족발 (pig's feet),\neven 찌개 in real dishes (returned later)."},
{type:"mc",q:"반찬 literally means:",opts:["Accompany-dish (side dishes)","Main course","Dessert","Appetizer"],ans:"Accompany-dish (side dishes)",hint:"반 + 찬. What role do they play alongside rice?"},
{type:"match",pairs:[{nl:"찌개",en:"thick stew"},{nl:"반찬",en:"side dishes"},{nl:"삼겹살",en:"pork belly"},{nl:"떡볶이",en:"spicy rice cakes"}]},
{type:"mc",q:"맛집 means:",opts:["Fast food","Famous restaurant (known for taste)","Cooking school","Food market"],ans:"Famous restaurant (known for taste)",hint:"맛 + 집(house). A place valued for its flavor."},
{type:"fb",s:"한국 사람들은 {1} 음식을 많이 시켜요.\n(Koreans order a lot of ___ food.)",a:"배달",opts:["배달","반찬","맛집","찌개"],hint:"시키다 = to order. What kind of food arrives at your door?"},
{type:"mc",q:"삼겹살 breaks down as:",opts:["Thin-slice-pork","Three-times-meat","Three-layer-meat","Grilled-meat-dish"],ans:"Three-layer-meat",hint:"삼겹살 is a compound noun: 삼 = 三 (how many?), 겹 = fold, 살 = flesh. Layers define the name."},
{type:"fb",s:"이 식당 {1}이에요! 줄을 서야 해요.\n(This restaurant is a famous ___! You have to wait in line.)",a:"맛집",opts:["맛집","배달","반찬","찌개"],hint:"A restaurant so famous people line up. 맛(taste) + 집(house)."},
{type:"drag_fill",s:"여름에 {1}을 먹고, 겨울에 {2}를 먹어요.\n(In summer I eat ___, in winter I eat ___.)",blanks:{"1":"냉면","2":"찌개"},pool:["냉면","찌개","배달","맛집","반찬"],hint:"Cold noodles suit summer. Boiling stew suits winter."},
{type:"match",pairs:[{nl:"냉면",en:"cold noodles"},{nl:"삼계탕",en:"ginseng chicken soup"},{nl:"맛집",en:"food destination"},{nl:"배달",en:"delivery"}]},
{type:"fb",s:"삼겹살 굽{1} 쉬워요. 양념만 있으면 돼요.\n(Grilling pork belly is easy. You just need seasoning.)",a:"기가",opts:["기가","기를","기에","는 것"],hint:"Grilling is the subject. -기 nominalization + subject particle."},
{type:"drag_fill",s:"이 {1}에서 {2}을 먹{3} 위해서 미리 예약해야 해요.\n(You need to reserve in advance in order to eat ___ at this ___.)",blanks:{"1":"맛집","2":"삼겹살","3":"기"},pool:["맛집","삼겹살","기","배달","반찬","는 것"],hint:"At a famous restaurant, to eat pork belly, you need a reservation. -기 위해서 = in order to."},
{type:"mc",q:"떡볶이 먹는 것을 좋아하는데, 찌개도 자주 시켜요 combines:",opts:["Two patterns","Only -는 것","Only -는데","Three: -는 것 + modifier (좋아하는) + -는데 (contrast)"],ans:"Three: -는 것 + modifier (좋아하는) + -는데 (contrast)",hint:"Identify the noun clause (-는 것), the relative clause attached to it, and the concessive connector."},

{type:"fb",s:"요리하{1} 쉽지 않지만 재미있어요.\n(Cooking is not easy but it is fun.)",a:["기는"],opts:["기는","는 것은","기가","는 것이"],hint:"-기 nominalizes the verb: 요리하기 = cooking (as noun)."},
{type:"mc",q:"한국어를 배우기 시작한 지 1년이 됐어요.\n(It has been 1 year since I started learning Korean.)",opts:["-기 (nominal) + -ㄴ 지","-는 것 + -(으)ㄴ 후에","-기 (nominal) + -기 전에","-는 것 + -다가"],ans:"-기 (nominal) + -ㄴ 지",hint:"Express how long it has been since starting something. Use two special forms."},
{type:"match",pairs:[{nl:"요리하기",en:"cooking (nominalized)"},{nl:"요리하는 것",en:"cooking (the act of)"},{nl:"요리한 음식",en:"food that was cooked"},{nl:"요리할 재료",en:"ingredients to cook"}]},
]},

// ── L3: -는 것 (21 steps) ──
{id:"kou18l3",title:"-는 것",icon:"📦",xp:24,board:true,steps:[
{type:"intro",title:"The Thing That...",desc:"-는 것\n→ the thing that, doing\n\n먹는 것 = eating.\nTurn whole clauses into noun phrases.",goals:["Use -는 것 for noun clauses","Combine with 좋아하다, 싫어하다","Express likes/dislikes about activities","Compare -는 것 with -기"]},
{type:"teach",nl:"굽다",en:"to grill, to roast",pos:"verb",gender:null,funFact:"To grill / bake / roast. Used for grilling meat (고기를 굽다) and baking bread (빵을 굽다). Also: to burn (방을 굽다 = to burn the room).",phonetic:"gup-da",example:"A: 삼겹살 구울까요?\nB: 네, 제가 구울게요.\nA: 잘 굽네요! 어디서 배웠어요?\nB: 아버지한테 배웠어요. 고기는 천천히 구워야 해요.\nA: 구운 고기 정말 맛있어요!",exampleEn:"A: Shall we grill pork belly?\nB: Yes, I will grill it.\nA: You grill well! Where did you learn?\nB: I learned from my father. You must grill meat slowly.\nA: Grilled meat is really delicious!",note:"굽다 → 구워요 (ㅂ-irregular).\nUsed for grilling meat, baking bread.\n구운 고기 = grilled meat.",kind:"word"},
{type:"teach",nl:"볶다",en:"to stir-fry",pos:"verb",gender:null,funFact:"To cook. Sino-Korean 料理 (ingredients-manage) + 하다. 요리 also means 'cuisine.' One of the most productive 하다 verbs in Korean.",phonetic:"bokk-da",example:"A: 볶음밥 만들어 볼까요?\nB: 좋아요! 먼저 야채를 볶아요.\nA: 어떤 야채를 볶을까요?\nB: 당근이랑 양파를 볶으세요.\nA: 맛있는 냄새가 나요!",exampleEn:"A: Shall we try making fried rice?\nB: Great! First stir-fry the vegetables.\nA: Which vegetables should we stir-fry?\nB: Please stir-fry carrots and onions.\nA: It smells delicious!",note:"볶다 → 볶아요 (regular).\n볶음밥 = fried rice.\n떡볶이 = stir-fried rice cakes.",kind:"word"},
{type:"tip",title:"-는 것: Clause to Noun",text:"Verb + -는 것 = the act of doing\n\n먹는 것 = eating\n하는 것 = doing\n보는 것 = watching\n\n먹는 것을 좋아해요.\n= I like eating.\n\n것 shortens to 거 in speech:\n먹는 거 좋아해요.",deepDive:"-는 것 vs -기 for 'doing':\n\nBoth work with 좋아하다/싫어하다:\n요리하는 것을 좋아해요. (common)\n요리하기를 좋아해요. (also correct)\n\n-는 것 is more versatile.\n-기 is more for fixed patterns.\n\n제가 하는 것 = what I do\n제가 먹은 것 = what I ate\n제가 할 것 = what I will do\n\nTense through the modifier:\n-는 (present), -(으)ㄴ (past), -(으)ㄹ (future)"},
{type:"mc",q:"먹는 것을 좋아해요 means:",opts:["I like eating","I eat things I like","I like food","I eat a lot"],ans:"I like eating",hint:"먹는 것 = the act of …. 좋아해요 = I …. The clause becomes a noun."},
{type:"fb",s:"한국 음식 만드{1} 것을 좋아해요.\n(I like making Korean food.)",a:"는",opts:["는","은","ㄴ","을"],hint:"Making is happening now, an ongoing preference. Which modifier marks present tense verbs?"},
{type:"mc",q:"어제 먹은 것 vs 지금 먹는 것 vs 내일 먹을 것:",opts:["All present tense","Past vs present vs future noun clause","All past tense","All future tense"],ans:"Past vs present vs future noun clause",hint:"Three different modifiers before 것 create three different time references."},
{type:"fb",s:"어제 먹{1} 것이 맛있었어요.\n(What I ate yesterday was delicious.)",a:"은",opts:["은","는","을","기"],hint:"Yesterday signals past tense. Which modifier form marks completed actions?"},
{type:"mc",q:"내일 할 것이 많아요 means:",opts:["I'm doing a lot now","I did a lot yesterday","I have a lot to do tomorrow","I don't have anything to do"],ans:"I have a lot to do tomorrow",hint:"할 = future modifier of 하다. 것 = thing. 많아요 = there are many."},
{type:"fb",s:"제가 좋아하{1} 것은 요리하는 것이에요.\n(The thing I like is cooking.)",a:"는",opts:["는","은","ㄴ","을"],hint:"Liking is an ongoing state. Which modifier form marks present actions?"},
{type:"tip",title:"것 to 거 in Speech",text:"In casual spoken Korean:\n\n것 → 거\n것이 → 게\n것을 → 걸\n\n먹는 것을 좋아해요 → 먹는 걸 좋아해요\n재미있는 것이 없어요 → 재미있는 게 없어요\n\nWritten: 것. Spoken: 거."},
{type:"mc",q:"먹는 걸 좋아해요 = 먹는 것을 좋아해요. 걸 is:",opts:["Past tense of 것","A different word","More formal","것을 shortened (casual speech)"],ans:"것을 shortened (casual speech)",hint:"In relaxed Korean, 것을 blends into a shorter spoken form. What do the syllables become?"},
{type:"fb",s:"삼겹살 굽{1} 것을 좋아해요.\n(I like grilling pork belly.)",a:"는",opts:["는","은","ㄴ","을"],hint:"Grilling is a present/habitual action. Which suffix makes a present-tense modifier?"},
{type:"drag_fill",s:"제가 {1} 것은 한국 음식 먹{2} 거예요.\n(The thing I like is eating Korean food.)",blanks:{"1":"좋아하는","2":"는"},pool:["좋아하는","는","좋아한","은","좋아할"],hint:"The thing I like (ongoing) is eating (ongoing). Both need present modifiers."},
{type:"match",pairs:[{nl:"먹는 것",en:"eating (present)"},{nl:"먹은 것",en:"what was eaten (past)"},{nl:"먹을 것",en:"what to eat (future)"},{nl:"먹기",en:"eating (abstract)"}]},
{type:"fb",s:"맛있{1} 것 추천해 주세요.\n(Please recommend something delicious.)",a:"는",opts:["는","은","을","기"],hint:"맛있다 is a descriptive verb. Which suffix creates its present modifier?"},
{type:"mc",q:"살기 좋은 곳 vs 사는 곳:",opts:["Good place to live vs place where you live","Both mean the same","살기 is formal, 사는 is casual","Only 사는 곳 is correct"],ans:"Good place to live vs place where you live",hint:"살기 좋은 evaluates quality abstractly. 사는 곳 simply names an inhabited location."},
{type:"drag_fill",s:"어제 {1} 찌개가 맛있었어요. 오늘도 {2} 거예요.\n(The stew I ate yesterday was delicious. I will eat it today too.)",blanks:{"1":"먹은","2":"먹을"},pool:["먹은","먹을","먹는","먹기","먹어"],hint:"Yesterday = past modifier. Today (plan) = future modifier. Both modify 것."},
{type:"mc",q:"구운 삼겹살을 먹는 것을 좋아해요 combines:",opts:["Only -는 것","Past modifier (구운) + -는 것 nominalization + 좋아하다","Only past modifier","Two -기 patterns"],ans:"Past modifier (구운) + -는 것 nominalization + 좋아하다",hint:"구운 reflects a completed grilling action. 먹는 것 wraps the eating clause into a noun."},
{type:"fb",s:"어제 볶{1} 것이 맛있었어요.\n(What I stir-fried yesterday was delicious.)",a:"은",opts:["은","는","을","기"],hint:"Yesterday = completed action. Which suffix creates a past-tense modifier for consonant stems?"},

{type:"fb",s:"건강해지{1} 위해서 매일 운동해요.\n(I exercise every day in order to become healthy.)",a:["기"],opts:["기","는","기로","게"],hint:"-기 위해서 = in order to. Formal purpose expression."},
{type:"mc",q:"좋은 성적을 받기 위해서 열심히 공부하고 있어요.\n(I am studying hard in order to get good grades.)",opts:["-기 위해서 + -기로 하다","-(으)려고 + -게 되다","-기 위해서 + -고 있다","-(으)려면 + -고 있다"],ans:"-기 위해서 + -고 있다",hint:"Formal purpose + progressive: working toward a goal."},
{type:"drag_fill",s:"한국어를 잘하{1} 위해서 매일 드라마를 {2}.\n(In order to speak Korean well, I watch dramas every day.)",blanks:{"1":"기","2":"봐요"},pool:["기","봐요","는","보기","게","보는"],hint:"-기 위해서 (formal purpose) + habitual present."},
{type:"mc",q:"환경을 보호하기 위해서 일회용품을 줄여야 해요.\n(In order to protect the environment, we must reduce disposables.)",opts:["-(으)려면 + -기로 하다","-(으)려고 + -아/어야 하다","-기 위해서 + -게 되다","-기 위해서 + -아/어야 하다"],ans:"-기 위해서 + -아/어야 하다",hint:"Formal purpose + obligation: in order to X, we must Y."},
{type:"match",pairs:[{nl:"-기 위해서",en:"in order to (formal)"},{nl:"-(으)려고",en:"in order to (casual)"},{nl:"-(으)려면",en:"if you want to"},{nl:"-(으)러 가다",en:"go to do"}]},
{type:"fb",s:"시험에 합격하{1} 위해서 하루에 8시간씩 공부했어요.\n(I studied 8 hours a day in order to pass the exam.)",a:["기"],opts:["기","는","게","기로"],hint:"-기 위해서: verb stem + 기 위해서 for formal purpose."},
]},

// ── L4: 맛집 문화 (21 steps) ──
{id:"kou18l4",title:"맛집 문화",icon:"🍜",xp:20,board:true,steps:[
{type:"intro",title:"Korean Food Culture",desc:"Koreans take food SERIOUSLY.\n\n맛집 hunting, 먹방, food delivery.\nFood is social glue in Korea.",goals:["Understand Korean food culture","Learn about 맛집 and 먹방","Discuss food preferences","Use food grammar naturally"]},
{type:"teach",nl:"먹방",en:"eating broadcast (mukbang)",pos:"noun",gender:null,funFact:"Online eating show (먹방). Compound: 먹(eat) + 방 (from 방송 = broadcast). A global Korean cultural export; hours of hosts eating large quantities.",phonetic:"meok-bang",example:"A: 어젯밤에 뭐 했어요?\nB: 먹방을 봤어요. 정말 재미있었어요.\nA: 어떤 먹방이었어요?\nB: 치킨 먹방이었어요. 보다가 배고파졌어요.\nA: 먹방 보면 항상 배고파져요!",exampleEn:"A: What did you do last night?\nB: I watched a mukbang. It was really fun.\nA: What kind of mukbang was it?\nB: It was a chicken mukbang. I got hungry while watching.\nA: Watching mukbang always makes you hungry!",note:"먹(eat) + 방송(broadcast).\nOnline eating show. Started in Korea.\nNow a global trend.",kind:"noun"},
{type:"teach",nl:"혼밥",en:"eating alone",pos:"noun",gender:null,funFact:"Solo meal (혼밥 = alone + meal). Was socially taboo in Korea pre-2015, now mainstream. 혼술 (drinking alone) and 혼카 (solo karaoke) followed.",phonetic:"hon-bap",example:"A: 점심 같이 먹을까요?\nB: 미안해요, 오늘은 혼밥할 거예요.\nA: 혼밥 괜찮아요?\nB: 요즘은 혼밥하는 사람이 많아요.\nA: 맞아요. 혼밥 식당도 많아졌어요.",exampleEn:"A: Shall we eat lunch together?\nB: Sorry, I will eat alone today.\nA: Is eating alone okay?\nB: These days many people eat alone.\nA: That is true. Solo-dining restaurants have increased too.",note:"혼자(alone) + 밥(rice/meal).\nEating alone. Was taboo, now accepted.\n혼밥 식당 = solo-dining restaurants.",kind:"noun"},
{type:"teach",nl:"야식",en:"late night snack",pos:"noun",gender:null,example:"A: 배고파요.\nB: 야식 시켜 먹을까요?",exampleEn:"A: I am hungry.\nB: Should we order a late night snack?",funFact:"Sino-Korean compound: 야(night/夜) + 식(food/食)",phonetic:"ya-sik",note:"COMPOUND: 야(night/夜) + 식(food/食).\nNight-food = late night snack.\n치킨 is Korea's #1 야식.",kind:"noun"},
{type:"teach",nl:"시키다",en:"to order (food/delivery)",pos:"verb",gender:null,funFact:"To order / make someone do. Used for ordering food (처볼를 시키다) or compelling someone (시키는 대로).",phonetic:"si-ki-da",example:"A: 배고프지 않아요?\nB: 배고파요! 배달 시킬까요?\nA: 좋아요. 뭐 시킬 거예요?\nB: 치킨이랑 피자 시킬까요?\nA: 치킨만 시켜요. 피자는 어제 먹었어요.",exampleEn:"A: Are you not hungry?\nB: I am hungry! Shall we order delivery?\nA: Sure. What will you order?\nB: Shall we order chicken and pizza?\nA: Let us just order chicken. We had pizza yesterday.",note:"시키다 → 시켜요 (polite present).\nUsed for ordering food, drinks.\n배달 시키다 = order delivery.",kind:"word"},
{type:"tip",title:"Korean Food Culture",text:"Food facts:\n- Koreans eat together (혼밥 was taboo)\n- Sharing dishes is the norm\n- Rice + soup + 반찬 = standard meal\n- 혼밥 (혼자 밥) now accepted\n- 먹방 (eating broadcast) is huge\n- 맛집 hunting has long lines",deepDive:"먹방 (mukbang) culture:\n\n먹(eat) + 방송(broadcast) = eating show.\nStarted in Korea around 2010.\nNow a global phenomenon.\n\nTypes:\n- ASMR 먹방: focus on eating sounds\n- 대식 먹방: eating huge amounts\n- 요리 먹방: cooking + eating\n- 리뷰 먹방: restaurant reviews"},
{type:"mc",q:"먹방 is:",opts:["An eating broadcast show","A type of food","A restaurant chain","A cooking method"],ans:"An eating broadcast show",hint:"먹방 is a portmanteau. 방 comes from 방송, which means airing content over media."},
{type:"fb",s:"요즘 {1}하는 사람이 많아요.\n(These days many people eat alone.)",a:"혼밥",opts:["혼밥","먹방","맛집","배달"],hint:"혼자 + 밥 = eating alone. Which compound word means this?"},
{type:"mc",q:"혼밥 was traditionally considered:",opts:["Very normal","Socially awkward/taboo (but now accepted)","Only for foreigners","A type of cooking"],ans:"Socially awkward/taboo (but now accepted)",hint:"Korean culture valued communal eating. Solo dining was unusual until recently."},
{type:"fb",s:"밤에 {1}으로 치킨을 시켜요.\n(At night I order chicken as a late-night snack.)",a:"야식",opts:["야식","혼밥","먹방","맛집"],hint:"밤 = night. 야(night) + 식(food). Which word means nighttime food?"},
{type:"match",pairs:[{nl:"먹방",en:"eating broadcast"},{nl:"혼밥",en:"eating alone"},{nl:"야식",en:"late night snack"},{nl:"맛집",en:"famous restaurant"}]},
{type:"mc",q:"한국에서 배달 음식 1위는:",opts:["햄버거","피자","치킨 (fried chicken)","중국 음식"],ans:"치킨 (fried chicken)",hint:"A famous Korean food combo: crispy poultry plus a fermented beverage."},
{type:"fb",s:"먹는 {1}을 좋아해요. 그래서 먹방을 자주 봐요.\n(I like eating. So I often watch mukbang.)",a:"것",opts:["것","기","데","거"],hint:"I like the act of eating. -는 + what turns the clause into a noun?"},
{type:"drag_fill",s:"맛있는 {1}을 찾기가 {2}. 리뷰를 봐야 해요.\n(Finding a famous restaurant is ___. You have to read reviews.)",blanks:{"1":"맛집","2":"어려워요"},pool:["맛집","어려워요","쉬워요","배달","재미있어요"],hint:"Finding a great restaurant is not easy. -기가 어렵다 = hard to do."},
{type:"fb",s:"야식 시키{1} 전에 뭐 먹고 싶은지 정하세요.\n(Before ordering a late-night snack, decide what you want.)",a:"기",opts:["기","는","은","어"],hint:"Before ordering. Which suffix combines with 전에 to mean 'before doing'?"},
{type:"mc",q:"혼밥하기가 편해졌어요 combines which patterns?",opts:["Past modifier + 것","Only -기","Only -아/어지다","-기 nominalization + -아/어지다 (became)"],ans:"-기 nominalization + -아/어지다 (became)",hint:"혼밥하기 makes the verb a subject noun. -지다 signals a gradual change of state."},
{type:"drag_fill",s:"배달 시키{1} 것이 요리하{2}보다 편해요.\n(Ordering delivery is more convenient than cooking.)",blanks:{"1":"는","2":"기"},pool:["는","기","은","는 것","을"],hint:"Ordering delivery (-는 것) vs cooking (-기). Two nominalizations compared."},
{type:"mc",q:"먹방을 보는 것을 좋아하는데 야식을 시키면 건강에 안 좋아요 combines:",opts:["Three: -는 것 + -는데 (contrast) + -(으)면 (conditional)","One pattern (in most cases) (in most cases) (in most cases)","Two patterns (in most cases) (in most cases)","Four patterns (in most cases) (in most cases)"],ans:"Three: -는 것 + -는데 (contrast) + -(으)면 (conditional)",hint:"Identify the noun clause, the concessive connector (-는데), and the hypothetical connector (-(으)면)."},
{type:"drag_fill",s:"혼밥하{1} 쉽지만, 배달 시키{2} 더 쉬워요.\n(Eating alone is easy, but ordering delivery is even easier.)",blanks:{"1":"기","2":"가"},pool:["기가","는 것","기를","기에"],hint:"Solo dining is the subject. -기 + subject marker 가."},
{type:"mc",q:"야식으로 시킨 음식이 건강에 안 좋다는 것을 알아요 combines:",opts:["Three (in most cases) (in most cases) (in most cases)","Four: modifier (시킨) + -는 것 + -다는 것 (fact clause) + 알다","Two (in most cases) (in most cases) (in most cases)","One (in most cases) (in most cases) (in most cases)"],ans:"Four: modifier (시킨) + -는 것 + -다는 것 (fact clause) + 알다",hint:"Count each grammar element: the -(으)ㄴ describing food, -는 것, the embedded -다는, and the main verb."},

{type:"mc",q:"맛집을 찾기 위해서 인터넷에서 검색해 봤어요.\n(I searched online in order to find a famous restaurant.)",opts:["-기 위해서 + -게 되다","-(으)려고 + -아/어 보다","-기 위해서 + -아/어 보다","-(으)려면 + -아/어야 하다"],ans:"-기 위해서 + -아/어 보다",hint:"Formal purpose + tried doing: searched in order to find."},
{type:"fb",s:"한국에서는 줄을 서서 {1} 식당이 맛있는 식당이에요.\n(In Korea, a restaurant where you line up to eat is a good restaurant.)",a:["먹는"],opts:["먹는","먹은","먹을","먹기"],hint:"Use the present tense modifier to describe the kind of place by what happens there."},
]},

// ── L5: ★ 관형형 HARVEST (21 steps) ──
{id:"kou18l5",title:"★ 관형형",icon:"🌾",xp:26,board:true,steps:[
{type:"intro",title:"Harvesting Noun Modifiers",desc:"You've been seeing modifiers since Unit 7.\n\n맛있는 음식 (delicious food)\n먹은 음식 (food I ate)\n먹을 음식 (food to eat)\n\nThe full modifier system.",goals:["Master present/past/future modifiers","Apply to verbs and adjectives","Build complex noun phrases","Use modifiers naturally in context"]},
{type:"teach",nl:"재료",en:"ingredient(s)",pos:"noun",gender:null,funFact:"Sino-Korean compound: 재(material/材) + 료(matter/料)",phonetic:"jae-ryo",example:"재료를 준비하세요.\n(Please prepare the ingredients.)",exampleEn:"Please prepare the ingredients.",note:"COMPOUND: 재(material/材) + 료(matter/料).\nMaterial-matter = ingredients.\n요리 재료 = cooking ingredients.",kind:"noun"},
{type:"teach",nl:"레시피",en:"recipe",pos:"noun",gender:null,funFact:"Loanword from English \"recipe.\" Korean adapted it using Hangul phonetics.",phonetic:"re-si-pi",example:"A: 이 요리 어떻게 만들었어요?\nB: 인터넷에서 레시피를 찾았어요.\nA: 레시피가 어려웠어요?\nB: 아니요, 쉬운 레시피를 골랐어요.\nA: 저한테도 그 레시피 보내 주세요!",exampleEn:"A: How did you make this dish?\nB: I found a recipe on the internet.\nA: Was the recipe difficult?\nB: No, I chose an easy recipe.\nA: Please send me that recipe too!",note:"Loanword from English 'recipe'.\n요리 레시피 = cooking recipe.\nKoreans often search 네이버 for recipes.",kind:"noun"},
{type:"tip",title:"The Three Modifier Tenses",text:"VERBS:\nPresent: -는 → 먹는 음식\nPast: -(으)ㄴ → 먹은 음식\nFuture: -(으)ㄹ → 먹을 음식\n\nADJECTIVES:\nPresent: -(으)ㄴ → 큰, 작은, 좋은\n맛있다 acts like verb → 맛있는\n\n이다 (copula):\nPresent: -인 → 학생인 사람",deepDive:"Verb present -는:\n먹다 → 먹는, 가다 → 가는\n\nVerb past -(으)ㄴ:\n먹다 → 먹은, 가다 → 간\n\nVerb future -(으)ㄹ:\n먹다 → 먹을, 가다 → 갈\n\nAdjective -(으)ㄴ (no tense):\n크다 → 큰, 작다 → 작은, 좋다 → 좋은"},
{type:"mc",q:"맛있는 음식 vs 맛있었던 음식:",opts:["Delicious food (now) vs food that was delicious (then)","Both present tense (in most cases) (in most cases)","Both past tense (in most cases) (in most cases)","Same meaning (in most cases) (in most cases) (in most cases)"],ans:"Delicious food (now) vs food that was delicious (then)",hint:"-는 = present state. -었던 = recalled past experience. Different time frames."},
{type:"fb",s:"어제 {1} 식당이 맛있었어요.\n(The restaurant I went to yesterday was delicious.)",a:"간",opts:["간","가는","갈","가"],hint:"Yesterday = past. 가다 past modifier: vowel stem + ㄴ directly."},
{type:"mc",q:"내일 먹을 음식을 준비해요 means:",opts:["I ate food yesterday for tomorrow","I'm preparing food to eat tomorrow","I'm preparing food I'm eating now","I already prepared the food"],ans:"I'm preparing food to eat tomorrow",hint:"내일 signals upcoming time. 먹을 attaches which -(으)ㄹ form to 먹다 for an unrealized action?"},
{type:"fb",s:"지금 먹{1} 음식이 맛있어요.\n(The food I'm eating now is delicious.)",a:"는",opts:["는","은","을","던"],hint:"지금 (now) = present. Verbs use which modifier for present tense?"},
{type:"mc",q:"큰 도시 vs 가는 사람. Why different endings?",opts:["크다 is past, 가다 is present","Both use the same pattern","크다 is adjective (-(으)ㄴ), 가다 is verb (-는)","Random difference"],ans:"크다 is adjective (-(으)ㄴ), 가다 is verb (-는)",hint:"Adjectives and verbs use different modifier endings for present tense."},
{type:"fb",s:"한국에서 {1} 음식 중에 김치가 가장 유명해요.\n(Among foods made in Korea, kimchi is the most famous.)",a:"만든",opts:["만든","만드는","만들","만들은"],hint:"Past modifier of 만들다. ㄹ drops before ㄴ in ㄹ-irregular verbs."},
{type:"tip",title:"Common Modifier Expressions",text:"자주 가는 식당 = restaurant I often go to\n좋아하는 음식 = food I like\n어제 먹은 것 = what I ate yesterday\n내일 할 일 = work to do tomorrow\n살고 싶은 나라 = country I want to live in\n\nModifiers go BEFORE the noun.\nOpposite to English relative clauses."},
{type:"mc",q:"좋아하는 음식이 뭐예요? means:",opts:["What food did you eat?","Is the food good?","Do you like food?","What food do you like?"],ans:"What food do you like?",hint:"좋아하는 = that you … (present modifier). 음식 = …. 뭐 = what."},
{type:"fb",s:"새로운 레시피로 만드{1} 음식이 맛있었어요.\n(The food I made with a new recipe was delicious.)",a:"ㄴ",opts:["ㄴ","는","ㄹ","기"],hint:"Made = completed action. 만들다 vowel stem gets which past ending?"},
{type:"drag_fill",s:"제가 자주 {1} 맛집에서 {2} 반찬이 정말 맛있어요.\n(At the restaurant I often go to, the side dishes that come out are really tasty.)",blanks:{"1":"가는","2":"나오는"},pool:["가는","나오는","간","나온","갈"],hint:"Going and coming out are both ongoing habits. Both need present modifiers."},
{type:"match",pairs:[{nl:"먹는 (present)",en:"eating / that eats"},{nl:"먹은 (past)",en:"ate / that ate"},{nl:"먹을 (future)",en:"will eat / to eat"},{nl:"큰 (adj present)",en:"big / that is big"}]},
{type:"fb",s:"제가 {1} 나라는 한국이에요.\n(The country I want to live in is Korea.)",a:"살고 싶은",opts:["살고 싶은","살고 싶는","사는","살은"],hint:"-고 싶다 acts like an adjective for modifiers. Adjectives take -(으)ㄴ."},
{type:"mc",q:"레시피에 나오는 재료를 살 거예요 combines:",opts:["Present modifier (나오는) + future modifier (살)","Only present","Only future","Past + present"],ans:"Present modifier (나오는) + future modifier (살)",hint:"나오는 describes an ongoing appearance. 살 거예요 signals a purchase not yet made. Which -(으)ㄹ form?"},
{type:"fb",s:"내일 {1} 재료를 오늘 사야 해요.\n(I need to buy ingredients to use tomorrow today.)",a:"쓸",opts:["쓸","쓰는","쓴","쓰기"],hint:"Tomorrow = future. 쓰다 future modifier: vowel stem + ㄹ = 쓸."},
{type:"mc",q:"맛있는 음식을 만들기 위해서 레시피를 찾아요 combines:",opts:["Two","Three: modifier (맛있는) + -기 위해서 + object","One","Four"],ans:"Three: modifier (맛있는) + -기 위해서 + object",hint:"맛있는 uses an adjective ending. -기 위해서 expresses purpose. Together with 찾아요, count the layers."},
{type:"drag_fill",s:"어제 {1} 레시피로 오늘 요리하{2} 것이 재미있을 거예요.\n(Cooking today with the recipe I found yesterday will be fun.)",blanks:{"1":"찾은","2":"는"},pool:["찾은","는","찾는","은","을"],hint:"Found yesterday = past modifier. Cooking today = present ongoing action. -는 것 nominalization."},

{type:"mc",q:"어제 읽은 책이 정말 재미있었어요.\n(The book I read yesterday was really interesting.)",opts:["읽을 (future modifier)","읽는 (present modifier)","읽은 (past modifier)","읽기 (nominalizer)"],ans:"읽은 (past modifier)",hint:"The reading is completed. 읽다 has a vowel stem, so -(으)ㄴ attaches directly. Which form?"},
]},

// ── L6: 관형형 연습 (21 steps) ──
{id:"kou18l6",title:"관형형 연습",icon:"🔧",xp:22,board:true,steps:[
{type:"intro",title:"Modifier Practice",desc:"Apply modifiers in food contexts.\n\nBuild complex descriptions\nusing all three tenses.",goals:["Practice all three modifier tenses","Build complex food descriptions","Combine modifiers with other grammar","Express preferences naturally"]},
{type:"teach",nl:"남다",en:"to remain, to be left over",pos:"verb",gender:null,funFact:"Native Korean verb, no hanja. 남다 → 남아요 (regular bright-vowel pattern). 남은 음식 = leftover food.",phonetic:"nam-da",example:"A: 음식이 많이 남았어요.\nB: 네, 너무 많이 만들었어요.\nA: 남은 음식은 어떻게 해요?\nB: 냉장고에 넣을게요. 내일 먹으면 돼요.\nA: 남은 찌개를 내일 데워 먹어요.",exampleEn:"A: A lot of food is left over.\nB: Yes, I made too much.\nA: What do we do with leftover food?\nB: I will put it in the fridge. We can eat it tomorrow.\nA: Let us heat up the leftover stew tomorrow.",note:"남다 → 남아요 (polite present).\n남은 음식 = leftover food.\n남은 반찬 = leftover side dishes.",kind:"word"},
{type:"teach",nl:"젓가락",en:"chopsticks",pos:"noun",gender:null,funFact:"Chopsticks. Korean chopsticks are metal, not wood/bamboo like Chinese/Japanese. Heavier and harder to use; harder for beginners but more hygienic.",phonetic:"jeot-ga-rak",example:"A: 한국 젓가락이 어려워요.\nB: 처음에는 다 어려워요. 연습하면 돼요.\nA: 왜 한국 젓가락은 금속이에요?\nB: 위생 때문이에요. 나무보다 깨끗해요.\nA: 젓가락으로 먹기가 점점 쉬워져요!",exampleEn:"A: Korean chopsticks are difficult.\nB: It is hard for everyone at first. Just practice.\nA: Why are Korean chopsticks made of metal?\nB: It is for hygiene. They are cleaner than wood.\nA: Eating with chopsticks is getting easier!",note:"Korean chopsticks are metal, not wood.\nFlat and thin, harder to use.\n숟가락 = spoon.",kind:"noun"},
{type:"mc",q:"매운 음식을 잘 먹는 사람 = a person who:",opts:["Eats spicy food well","Made spicy food","Will eat spicy food","Likes spicy people"],ans:"Eats spicy food well",hint:"먹는 = present modifier. 사람 = person. Habitual ability."},
{type:"fb",s:"엄마가 만들{1} 음식이 가장 맛있어요.\n(Food mom made for me is the most delicious.)",a:"어 준",opts:["어 준","는","은","을"],hint:"Mom made food FOR me. The benefactive -아/어 주다 in past modifier form."},
{type:"mc",q:"먹어 본 음식 vs 먹을 음식:",opts:["Both past","Food I've tried vs food to eat","Both future","Same meaning"],ans:"Food I've tried vs food to eat",hint:"먹어 보다 uses -아/어 보다 for experience. 먹을 uses -(으)ㄹ for an upcoming action."},
{type:"fb",s:"다음에 {1} 식당을 알려 주세요.\n(Please tell me a restaurant to go to next time.)",a:"갈",opts:["갈","가는","간","가"],hint:"Next time = future plan. 가다 future modifier: vowel stem + ㄹ."},
{type:"drag_fill",s:"{1} 반찬이 많은 식당이 {2} 식당이에요.\n(A restaurant with delicious side dishes is a good restaurant.)",blanks:{"1":"맛있는","2":"좋은"},pool:["맛있는","좋은","맛있은","좋는","맛있을"],hint:"Delicious = 맛있다 (verb-like, -는). Good = 좋다 (adjective, -(으)ㄴ)."},
{type:"mc",q:"배달시킨 음식 means:",opts:["Food to deliver (in most cases)","Food being delivered now (in most cases)","Food that was ordered for delivery","Delivery service (in most cases)"],ans:"Food that was ordered for delivery",hint:"배달시키다 + past modifier -(으)ㄴ = 배달시킨. The ordering is done."},
{type:"fb",s:"한국에서 가장 많이 {1} 배달 음식은 치킨이에요.\n(The most frequently ordered delivery food in Korea is chicken.)",a:"시키는",opts:["시키는","시킨","시킬","시켜"],hint:"A general ongoing fact. Which tense for habitual truths?"},
{type:"match",pairs:[{nl:"자주 가는 식당",en:"restaurant I often go to"},{nl:"어제 먹은 음식",en:"food I ate yesterday"},{nl:"내일 만들 요리",en:"dish to make tomorrow"},{nl:"좋아하는 반찬",en:"side dishes I like"}]},
{type:"fb",s:"남{1} 음식은 냉장고에 넣으세요.\n(Please put leftover food in the fridge.)",a:"은",opts:["은","는","을","기"],hint:"Food that remained = completed event. Which suffix creates a past modifier for consonant stems?"},
{type:"drag_fill",s:"제가 {1} 한국 음식은 떡볶이예요. 매운 {2} 좋아해요.\n(The Korean food I like most is tteokbokki. I like spicy things.)",blanks:{"1":"가장 좋아하는","2":"것을"},pool:["가장 좋아하는","것을","가장 좋아한","것이","좋아할"],hint:"Food I like most (present modifier). Spicy things (modifier + 것 + object particle)."},
{type:"fb",s:"어제 만{1} 요리가 맛있더라고요.\n(The dish I made yesterday was tasty, I found.)",a:"든",opts:["든","드는","들","들은"],hint:"만들다 past modifier. ㄹ drops before ㄴ. 만들 + ㄴ = 만든."},
{type:"mc",q:"젓가락으로 먹기 어려운 음식이 뭐예요? combines:",opts:["Past tense question (in most cases)","Only -기 (in most cases) (in most cases)","Only modifier (in most cases) (in most cases)","-기 어렵다 (hard to do) + modifier + question"],ans:"-기 어렵다 (hard to do) + modifier + question",hint:"어렵다 is a descriptive verb. Which adjective suffix turns it into a noun-describing form?"},
{type:"drag_fill",s:"맛있{1} 음식을 먹{2} 기분이 {3}.\n(When I eat delicious food, my mood gets better.)",blanks:{"1":"는","2":"으면","3":"좋아져요"},pool:["는","으면","좋아져요","은","으면서","좋아해요"],hint:"Delicious = present modifier. If/when = conditional. Gets better = -아/어지다."},
{type:"mc",q:"남은 재료로 만든 요리 has how many modifiers?",opts:["Two: 남은 (leftover) + 만든 (made)","One","Three","Zero"],ans:"Two: 남은 (leftover) + 만든 (made)",hint:"남은 and 만든 both use completed-action endings on their verbs. Which nouns do they describe?"},
{type:"fb",s:"젓가락으로 먹{1} 어려운 음식이 많아요.\n(There are many foods hard to eat with chopsticks.)",a:"기",opts:["기","는","은","을"],hint:"Hard to eat with chopsticks. Which nominalizing suffix pairs with 어렵다?"},
{type:"mc",q:"오늘 남은 음식으로 내일 먹을 반찬을 만들 거예요 combines:",opts:["Two (in most cases) (in most cases) (in most cases) (in most cases)","Three: past modifier (남은) + future modifier (먹을) + future plan (거예요)","One (in most cases) (in most cases) (in most cases) (in most cases)","Four (in most cases) (in most cases) (in most cases) (in most cases)"],ans:"Three: past modifier (남은) + future modifier (먹을) + future plan (거예요)",hint:"남은 describes what remains. 먹을 describes intended use. 거예요 expresses intent. How many layers?"},
{type:"drag_fill",s:"제가 {1} 음식 중에 가장 만들{2} 어려운 것은 찌개예요.\n(Among the foods I like, the hardest one to make is stew.)",blanks:{"1":"좋아하는","2":"기"},pool:["좋아하는","기","좋아한","는 것","좋아할"],hint:"Foods I like = present modifier. Hard to make = -기 어렵다. Two grammar patterns."},

{type:"fb",s:"내일 {1} 음식을 미리 준비해야 해요.\n(I must prepare the food to eat tomorrow in advance.)",a:["먹을"],opts:["먹을","먹는","먹은","먹기"],hint:"Apply the future modifier to the eating verb when describing planned food."},
{type:"drag_fill",s:"어제 {1} 식당이 오늘 {2} 식당보다 맛있었어요.\n(The restaurant I went to yesterday was tastier than the one I went to today.)",blanks:{"1":"간","2":"간"},pool:["간","간","가는","가는","갈","갈"],hint:"Past modifier for both: 가다 → 간. The restaurant that was visited."},
]},

// ── L7: -자고/-라고 복습 (21 steps) ──
{id:"kou18l7",title:"-자고/-라고 복습",icon:"💬",xp:20,board:true,steps:[
{type:"intro",title:"Food Conversations: Indirect Speech",desc:"Review indirect speech\nin food and restaurant contexts.",goals:["Review -자고 (suggested) in food contexts","Review -(으)라고 (told) in food contexts","Combine with modifiers and nominalization","Natural food conversation practice"]},
{type:"teach",nl:"추천하다",en:"to recommend",pos:"verb",gender:null,funFact:"Sino-Korean compound: 추(push/推) + 천(recommend/薦)",phonetic:"chu-cheon-ha-da",example:"이 식당을 추천해요.\n(I recommend this restaurant.)",exampleEn:"I recommend this restaurant.",note:"COMPOUND: 추(push/推) + 천(recommend/薦).\n추천하다 → 추천해요.\n맛집을 추천하다 = recommend a restaurant.",kind:"word"},
{type:"teach",nl:"주문하다",en:"to order (at a restaurant)",pos:"verb",gender:null,funFact:"Sino-Korean compound: 주(note/注) + 문(writing/文)",phonetic:"ju-mun-ha-da",example:"비빔밥을 주문했어요.\n(I ordered bibimbap.)",exampleEn:"I ordered bibimbap.",note:"COMPOUND: 주(note/注) + 문(writing/文).\n주문하다 → 주문해요.\nMore formal than 시키다.",kind:"word"},
{type:"mc",q:"친구가 맛집에 가자고 했어요 means:",opts:["My friend suggested going to a famous restaurant","My friend went to a restaurant (in most cases)","I suggested going (in most cases) (in most cases)","My friend asked about the restaurant"],ans:"My friend suggested going to a famous restaurant",hint:"-자고 했어요 = … doing. The … proposed the plan."},
{type:"fb",s:"의사가 매운 음식을 먹지 {1} 했어요.\n(The doctor told me not to eat spicy food.)",a:"말라고",opts:["말라고","자고","다고","냐고"],hint:"The doctor told me NOT to eat spicy food. Negative command in reported speech."},
{type:"mc",q:"리뷰에 맛있대요 means:",opts:["Is it delicious?","Reviews say it's delicious","I said it's delicious","Make it delicious"],ans:"Reviews say it's delicious",hint:"맛있대요 = 맛있다고 해요 shortened. Someone else's reported statement."},
{type:"fb",s:"친구가 이 식당 가 봤{1} 물어봤어요.\n(My friend asked if I have been to this restaurant.)",a:"냐고",opts:["냐고","다고","라고","자고"],hint:"Asking a yes/no question in reported speech. Which ending marks questions?"},
{type:"drag_fill",s:"엄마가 밥 {1} 하셨어요. 그리고 일찍 {2} 하셨어요.\n(Mom told me to eat rice. And told me to sleep early.)",blanks:{"1":"먹으라고","2":"자라고"},pool:["먹으라고","자라고","먹자고","자고","먹냐고"],hint:"Mom gave commands: eat rice, sleep early. Commands in reported speech: -(으)라고."},
{type:"match",pairs:[{nl:"먹자고 (suggested)",en:"suggested eating"},{nl:"먹으라고 (told)",en:"told to eat"},{nl:"먹었다고 (stated)",en:"said ate"},{nl:"먹었냐고 (asked)",en:"asked if ate"}]},
{type:"mc",q:"맛있는 거 먹자고 했어요. 먹자고 is:",opts:["Reported statement","Reported command","Reported suggestion (suggested eating)","Reported question"],ans:"Reported suggestion (suggested eating)",hint:"-자고 is the quotation ending for a group proposal. Not an order or directive."},
{type:"fb",s:"배달 음식 시키{1} 했는데 뭐 먹고 싶어요?\n(I suggested ordering delivery food. What do you want to eat?)",a:"자고",opts:["자고","라고","다고","냐고"],hint:"I suggested we order delivery food. Which ending reports a 'let's do' suggestion?"},
{type:"drag_fill",s:"A: 뭐 먹을래요?\nB: 친구가 삼겹살이 맛있{1}.\nA: 그러면 삼겹살 먹{2}!\n(A: What shall we eat?\nB: Friend says samgyeopsal is tasty.\nA: Then let's eat samgyeopsal!)",blanks:{"1":"대요","2":"자고요"},pool:["대요","자고요","냬요","래요","다고요"],hint:"Friend says (reported statement) = 대요. Let's eat (suggestion) = 자고요."},
{type:"fb",s:"삼겹살 먹{1} 식당에 갔어요.\n(I went to a restaurant to eat samgyeopsal.)",a:"으러",opts:["으러","으려고","으면서","어서"],hint:"Purpose of going: -(으)러 가다."},
{type:"mc",q:"매운 거 못 먹잖아요 means:",opts:["Spicy food is outside","Can you eat spicy food?","I ate spicy food","You can't eat spicy food, you know"],ans:"You can't eat spicy food, you know",hint:"-잖아요 = reminding someone of shared knowledge."},
{type:"fb",s:"친구가 맛있는 맛집을 {1} 해 줬어요.\n(My friend recommended a delicious famous restaurant for me.)",a:"추천",opts:["추천","주문","배달","시키"],hint:"My friend gave a restaurant recommendation. Which word means to recommend?"},
{type:"drag_fill",s:"의사가 야식 먹지 {1} 했는데, 친구가 치킨 시키{2} 해서 고민이에요.\n(The doctor told me not to eat late-night snacks, but my friend suggested ordering chicken, so I'm torn.)",blanks:{"1":"말라고","2":"자고"},pool:["말라고","자고","다고","냐고","먹으라고"],hint:"Doctor's negative command (-지 말라고) vs friend's suggestion (-자고). Conflicting advice."},
{type:"mc",q:"주문한 음식이 맛있었다고 했어요 combines:",opts:["Past modifier (주문한) + reported statement (-다고)","Only modifier (in most cases) (in most cases)","Only reported speech (in most cases)","Only past tense (in most cases) (in most cases)"],ans:"Past modifier (주문한) + reported statement (-다고)",hint:"주문한 uses -(으)ㄴ for completed ordering. -다고 embeds what someone communicated."},
{type:"fb",s:"친구가 매운 것 많이 먹{1} 했어요.\n(My friend told me to eat a lot of spicy things.)",a:"으라고",opts:["으라고","자고","다고","냐고"],hint:"A command in reported speech. Telling someone to eat = -(으)라고."},
{type:"mc",q:"삼겹살 구워서 반찬이랑 같이 먹자고 하는 것이 한국 문화예요 combines:",opts:["Three (in most cases) (in most cases)","Four: ㅂ-irregular (구워서) + -자고 + -는 것 + 이다","Two (in most cases) (in most cases) (in most cases)","One (in most cases) (in most cases)"],ans:"Four: ㅂ-irregular (구워서) + -자고 + -는 것 + 이다",hint:"Count the layers: grilling verb (consonant change) + group suggestion + verb-to-noun + linking verb."},
{type:"drag_fill",s:"의사가 야식을 줄이{1} 했는데, 친구가 치킨 시키{2} 해요.\n(The doctor told me to reduce late-night snacks, but my friend suggests ordering chicken.)",blanks:{"1":"라고","2":"자고"},pool:["라고","자고","다고","냐고","는데"],hint:"Doctor commands (-(으)라고). Friend suggests (-자고). Two kinds of reported speech."},

{type:"mc",q:"엄마가 맛있는 음식을 많이 만들어 주시라고 할머니께 부탁했어요.\n(Mom asked grandma to make a lot of delicious food.)",opts:["-다고 하다 (statement)","-자고 하다 (suggestion)","-(으)라고 하다 (command/request)","-냐고 하다 (question)"],ans:"-(으)라고 하다 (command/request)",hint:"Reported speech for requests uses a different ending than for statements."},
{type:"fb",s:"친구가 이 식당이 맛있{1} 추천했어요.\n(My friend recommended this restaurant saying it was delicious.)",a:["다고"],opts:["다고","라고","냐고","자고"],hint:"Report what someone said about the food using the statement quotation pattern."},
]},

// ── L8: 음식 대화 (21 steps) ──
{id:"kou18l8",title:"음식 대화",icon:"🗣️",xp:22,board:true,steps:[
{type:"intro",title:"Food Conversations",desc:"All Unit 18 grammar combined\nin natural food conversations.",goals:["Use nominalization naturally","Apply modifiers in food context","Combine all patterns fluently","Have natural food discussions"]},
{type:"teach",nl:"맵다",en:"to be spicy",pos:"verb",gender:null,funFact:"To be spicy. Modifier form: 매운 (spicy). Korean food is known for 매운 맛; famous spicy dishes include 떡볶이 and 불닭.",phonetic:"maep-da",example:"A: 이 떡볶이 매워요?\nB: 네, 좀 매워요. 괜찮아요?\nA: 매운 음식을 잘 못 먹어요.\nB: 그러면 덜 매운 걸로 시킬까요?\nA: 네, 안 매운 게 좋겠어요.",exampleEn:"A: Is this tteokbokki spicy?\nB: Yes, it is a little spicy. Is that okay?\nA: I cannot eat spicy food well.\nB: Then shall we order something less spicy?\nA: Yes, something not spicy would be good.",note:"맵다 → 매워요 (ㅂ-irregular).\nModifier: 매운 (spicy).\n매운 음식 = spicy food.",kind:"word"},
{type:"teach",nl:"싱겁다",en:"to be bland",pos:"verb",gender:null,funFact:"To be bland/undersalted. Opposite: 짜다 (salty). Contrasts on the savory axis: 달다 (sweet), 쓰다 (bitter), 신다 (sour), 매웍다 (spicy).",phonetic:"sing-geop-da",example:"A: 이 국 맛이 어때요?\nB: 좀 싱거워요. 소금을 넣을까요?\nA: 네, 좀 싱거운 것 같아요.\nB: 양념을 더 넣으면 맛있어질 거예요.\nA: 이제 괜찮아요. 싱겁지 않아요!",exampleEn:"A: How does this soup taste?\nB: It is a bit bland. Shall I add salt?\nA: Yes, it seems a little bland.\nB: If we add more seasoning it will get tasty.\nA: Now it is fine. It is not bland!",note:"싱겁다 → 싱거워요 (ㅂ-irregular).\nOpposite: 짜다 (salty).\n양념이 싱겁다 = seasoning is bland.",kind:"word"},
{type:"mc",q:"먹는 것을 좋아하는 편이에요. How many grammar points?",opts:["Three: -는 것 + 좋아하는 (modifier) + 편이에요 (tendency)","One","Two","Four"],ans:"Three: -는 것 + 좋아하는 (modifier) + 편이에요 (tendency)",hint:"먹는 것 wraps the clause, 좋아하는 describes it, and 편이에요 softens the overall claim."},
{type:"fb",s:"제가 가장 좋아하{1} 음식은 떡볶이예요.\n(The food I like most is tteokbokki.)",a:"는",opts:["는","은","ㄴ","을"],hint:"Liking is an ongoing state. Which modifier marks present tense verbs?"},
{type:"mc",q:"어제 먹은 삼겹살이 맛있었거든요 has two grammar layers:",opts:["Only past tense (in most cases) (in most cases) (in most cases)","먹은 (past modifier) + -거든요 (you see, giving new info)","Only -거든요 (맥락에서) (맥락에서) (맥락에서) (맥락에서) (맥락에서) (맥락에서)","Only the modifier (in most cases) (in most cases)"],ans:"먹은 (past modifier) + -거든요 (you see, giving new info)",hint:"먹은 marks a completed action on a noun. -거든요 gives background context the listener may not know."},
{type:"drag_fill",s:"맛있{1} 것 추천해 주세요. 매운 것 말고 안 매운 {2}요.\n(Please recommend something delicious. Not spicy, something not spicy.)",blanks:{"1":"는","2":"거"},pool:["는","거","은","기","것을"],hint:"Something delicious (verb-like modifier). Something not spicy (거 = casual 것)."},
{type:"fb",s:"한국 음식 만들{1} 어렵지만 재미있어요.\n(Making Korean food is difficult but fun.)",a:"기가",opts:["기가","기를","기에","는 것"],hint:"Making Korean food is the subject. -기 + subject marker 가."},
{type:"mc",q:"배달시킬 거예요 vs 배달시킨 거예요:",opts:["Both past","Both future","Will order delivery vs already ordered delivery","Same meaning"],ans:"Will order delivery vs already ordered delivery",hint:"시킬 거예요 expresses intention. 시킨 거예요 reports completion. Which suffix marks each?"},
{type:"match",pairs:[{nl:"-기 전에",en:"before doing"},{nl:"-는 것",en:"the act of doing"},{nl:"-(으)ㄴ 것",en:"what was done"},{nl:"-(으)ㄹ 것",en:"what will be done"}]},
{type:"fb",s:"자주 {1} 맛집에서 새로운 메뉴가 나왔대요.\n(At the restaurant I often go to, a new menu came out, they say.)",a:"가는",opts:["가는","간","갈","가"],hint:"Often going = habitual action. Present modifier for ongoing habits."},
{type:"drag_fill",s:"먹{1} 전에 손 씻으세요. {2} 음식은 냉장고에 넣으세요.\n(Wash hands before eating. Put leftover food in the fridge.)",blanks:{"1":"기","2":"남은"},pool:["기","남은","먹는","남는","기를"],hint:"-기 전에 = before doing. 남은 = leftover (past modifier of 남다)."},
{type:"fb",s:"이 찌개가 좀 싱거{1} 양념을 더 넣어야 해요.\n(This stew is a bit bland, so I need to add more seasoning.)",a:"워서",opts:["워서","우면","운데","울"],hint:"Because it's bland. ㅂ-irregular: 싱겁다 → 싱거워서 (cause/reason)."},
{type:"mc",q:"매운 것을 잘 먹는 사람이 부러워요 combines:",opts:["Two patterns total","Only one modifier","Only nominalization","Modifier (매운) + -는 것 + modifier (먹는) + adjective"],ans:"Modifier (매운) + -는 것 + modifier (먹는) + adjective",hint:"매운 uses a descriptive-word ending. 먹는 uses an action-word ending. Both come before nouns."},
{type:"fb",s:"맛집에 도착하{1} 바로 주문했어요.\n(As soon as I arrived at the famous restaurant, I ordered right away.)",a:"자마자",opts:["자마자","고 나서","ㄴ 후에","면서"],hint:"Arrived and IMMEDIATELY ordered. Which connector shows instant sequence?"},
{type:"drag_fill",s:"매{1} 음식을 먹{2} 위해서 물을 많이 {3}.\n(In order to eat spicy food, I prepare a lot of water.)",blanks:{"1":"운","2":"기","3":"준비해요"},pool:["운","기","준비해요","는","는 것","마셔요"],hint:"Spicy = adj modifier. In order to eat = -기 위해서. Prepare = action."},
{type:"mc",q:"맛집에서 주문한 매운 찌개가 싱거웠다고요? has how many layers?",opts:["Four: past modifier + adj modifier + ㅂ-irregular + reported surprise","Three (in most cases) (in most cases) (in most cases) (in most cases)","Two (in most cases) (in most cases) (in most cases) (in most cases)","One (in most cases) (in most cases) (in most cases) (in most cases)"],ans:"Four: past modifier + adj modifier + ㅂ-irregular + reported surprise",hint:"주문한 uses -(으)ㄴ, 매운 uses adjective -(으)ㄴ, 싱겁다 changes its ㅂ stem, and 다고요 signals disbelief."},
{type:"fb",s:"매운 음식 먹{1} 좋아해요. 땀이 나요.\n(I like eating spicy food. I sweat.)",a:"는 것을",opts:["는 것을","기를","은 것을","는 것이"],hint:"I like the act of eating. -는 것 + object particle 을."},
{type:"mc",q:"싱거운 찌개에 양념을 넣은 후에 맛이 좋아졌어요 combines:",opts:["Two (in most cases) (in most cases) (in most cases) (in most cases)","Three: ㅂ-irregular (싱거운) + past modifier (넣은) + -아/어졌어요 (became)","One (in most cases) (in most cases) (in most cases)","Four (in most cases) (in most cases) (in most cases)"],ans:"Three: ㅂ-irregular (싱거운) + past modifier (넣은) + -아/어졌어요 (became)",hint:"싱겁다 has a ㅂ stem change. 넣은 uses -(으)ㄴ for completed addition. -아/어지다 signals a result."},
{type:"drag_fill",s:"매{1} 음식을 먹{2} 전에 물을 준비하는 {3} 중요해요.\n(Preparing water before eating spicy food is important.)",blanks:{"1":"운","2":"기","3":"것이"},pool:["운","기","것이","는","것을","은"],hint:"Spicy = adj modifier. Before eating = -기 전에. The act of preparing = -는 것. Three patterns."},

{type:"fb",s:"A: 뭘 주문할까요? B: 비빔밥을 {1} 볼까요?\n(A: What shall we order? B: Shall we try bibimbap?)",a:["먹어"],opts:["먹어","먹고","먹기","먹을"],hint:"-아/어 보다 (try) + -(으)ㄹ까요 (suggestion): shall we try eating?"},
{type:"mc",q:"이 김치는 어머니가 직접 담그신 김치예요.\n(This kimchi is kimchi that mother personally made.)",opts:["담그시다 + -(으)ㄹ (future modifier)","담그다 + -는 (present modifier)","담그시다 + -(으)ㄴ (past modifier + honorific)","담그다 + -기 (nominalizer)"],ans:"담그시다 + -(으)ㄴ (past modifier + honorific)",hint:"담그시다 carries the -(으)시- infix. When it describes a completed noun action, which -(으)ㄴ form attaches?"},
{type:"match",pairs:[{nl:"매운 음식",en:"spicy food"},{nl:"달콤한 음식",en:"sweet food"},{nl:"싱거운 음식",en:"bland food"},{nl:"짠 음식",en:"salty food"}]},
]},

// ── L9: 복습 + 퀴즈 (21 steps) ──
{id:"kou18l9",title:"복습 + 퀴즈",icon:"📝",xp:20,board:true,steps:[
{type:"intro",title:"Unit 18 Review",desc:"Review nominalization and modifiers.\n\n-기, -는 것, modifiers -(으)ㄴ/는/(으)ㄹ.\nAll combined in food contexts.",goals:["Review -기 nominalization","Test modifier forms","Combine multiple grammar patterns","Complete nominalization mastery"]},
{type:"mc",q:"요리하기 쉬워요 = Cooking is easy. -기 here is:",opts:["Nominalizer (turns verb to noun)","Modifier (in most cases)","Past tense marker (in most cases)","Question marker (in most cases)"],ans:"Nominalizer (turns verb to noun)",hint:"-기 converts an action into a grammatical subject. What word category does this suffix create?"},
{type:"fb",s:"여행하{1} 것이 취미예요.\n(Traveling is my hobby.)",a:"는",opts:["는","은","을","기"],hint:"Traveling is an ongoing activity. Which suffix makes a present-tense modifier?"},
{type:"mc",q:"어제 먹은 것 vs 먹는 것 vs 먹을 것:",opts:["All present","Past vs present vs future","All past","Random variation"],ans:"Past vs present vs future",hint:"Three modifier forms create three time references before 것."},
{type:"match",pairs:[{nl:"찌개",en:"thick stew"},{nl:"반찬",en:"side dishes"},{nl:"먹방",en:"eating broadcast"},{nl:"양념",en:"seasoning"}]},
{type:"fb",s:"먹{1} 전에 손을 씻으세요.\n(Before eating, wash your hands.)",a:"기",opts:["기","는","은","을"],hint:"Before eating. Which suffix combines with 전에 for 'before doing'?"},
{type:"mc",q:"좋아하는 음식 = food I like. 좋아하는 is:",opts:["Future modifier","Past modifier","Present verb modifier","Adjective modifier"],ans:"Present verb modifier",hint:"좋아하다 describes an ongoing state, not a fixed property. Which suffix do action words take for describing?"},
{type:"drag_fill",s:"제가 {1} 반찬은 김치예요. 매일 {2} 거예요.\n(The side dish I like most is kimchi. I eat it every day.)",blanks:{"1":"가장 좋아하는","2":"먹는"},pool:["가장 좋아하는","먹는","좋아한","먹은","좋아할"],hint:"Like most (present modifier). Eat every day (present modifier). Both ongoing."},
{type:"fb",s:"재미있{1} 영화를 추천해 주세요.\n(Please recommend a fun movie.)",a:"는",opts:["는","은","을","기"],hint:"재미있다 is a descriptive verb. Which suffix creates its present modifier?"},
{type:"mc",q:"혼밥 means:",opts:["Fast food","Eating a lot","Eating together","Eating alone (혼자 밥)"],ans:"Eating alone (혼자 밥)",hint:"혼(자) = …. 밥 = meal/rice. A compound for solo dining."},
{type:"match",pairs:[{nl:"-기 전에",en:"before doing"},{nl:"-기 쉽다",en:"easy to do"},{nl:"-는 것",en:"the thing of doing"},{nl:"-기로 하다",en:"decide to do"}]},
{type:"fb",s:"찌개가 싱거{1} 양념을 더 넣었어요.\n(The stew was bland, so I added more seasoning.)",a:"워서",opts:["워서","우면","운데","울"],hint:"Because it was bland. ㅂ-irregular: 싱겁다 → 싱거워서."},
{type:"mc",q:"배달시킨 음식이 왔어요. 시킨 is:",opts:["Past modifier (food that was ordered)","Present modifier (in most cases)","Future modifier (in most cases)","Passive form (in most cases) (in most cases)"],ans:"Past modifier (food that was ordered)",hint:"시키다 ends in -하다 pattern. When the action is completed and describes a noun, which ending attaches?"},
{type:"drag_fill",s:"한국에서 {1} 음식을 골라 보세요. {2} 것을 추천해요.\n(Choose food you want to eat in Korea. I recommend spicy things.)",blanks:{"1":"먹고 싶은","2":"매운"},pool:["먹고 싶은","매운","먹는","맛있은","싶는"],hint:"Want to eat = -고 싶은 (adjective-like modifier). Spicy = 매운 (adjective modifier)."},
{type:"fb",s:"맛집에서 주문{1} 음식이 싱거웠어요.\n(The food I ordered at the famous restaurant was bland.)",a:"한",opts:["한","하는","할","하기"],hint:"I ordered = completed action. 주문하다 past modifier: 하 + ㄴ = 한."},
{type:"mc",q:"양념을 넣기 전에 재료를 볶는 것이 중요해요 combines:",opts:["Two patterns","Three: -기 전에 + -는 것 + 중요하다","One pattern","Four patterns"],ans:"Three: -기 전에 + -는 것 + 중요하다",hint:"Identify the 전에 expression, the -는 것 clause, and the importance verb. Count the patterns."},
{type:"drag_fill",s:"어제 {1} 맛집에서 {2} 떡볶이가 매{3} 못 먹었어요. 다음에는 안 매운 걸 {4} 거예요.\n(The tteokbokki I ordered at the restaurant I went to yesterday was too spicy so I couldn't eat it. Next time I'll order something not spicy.)",blanks:{"1":"간","2":"시킨","3":"워서","4":"시킬"},pool:["간","시킨","워서","시킬","가는","시키는","우면","시켜"],hint:"Went (past: 간). Ordered (past: 시킨). Because spicy (ㅂ-irregular: 매워서). Will order (future: 시킬). Four patterns."},
{type:"fb",s:"냉면 먹{1} 좋은 계절은 여름이에요.\n(The good season for eating cold noodles is summer.)",a:"기",opts:["기","는","은","을"],hint:"Good for eating cold noodles. Which suffix turns 먹다 into a noun here?"},
{type:"mc",q:"아침에 먹을 반찬을 어제 만들어 놓은 것이 남아 있어요 combines:",opts:["Two (in most cases) (in most cases) (in most cases) (in most cases)","Three (in most cases) (in most cases) (in most cases)","Four: future mod (먹을) + past mod (만들어 놓은) + -는 것 + -아 있다","One (in most cases) (in most cases) (in most cases)"],ans:"Four: future mod (먹을) + past mod (만들어 놓은) + -는 것 + -아 있다",hint:"먹을 describes intended use. 만들어 놓은 describes advance preparation. 남아 있다 states it remains. How many layers?"},
{type:"drag_fill",s:"친구가 {1} 맛집에서 {2} 음식이 매{3} 못 먹었{4} 했어요.\n(My friend said the food at the restaurant I recommended was too spicy and they could not eat it.)",blanks:{"1":"추천한","2":"시킨","3":"워서","4":"다고"},pool:["추천한","시킨","워서","다고","추천하는","시키는","우니까","라고"],hint:"Recommended (past mod). Ordered (past mod). Because spicy (ㅂ-irregular). Said (다고). Four patterns."},

{type:"mc",q:"한국 음식을 먹기 위해서 한국에 왔어요.\n(I came to Korea in order to eat Korean food.)",opts:["-(으)려면","-(으)려고","-(으)러","-기 위해서"],ans:"-기 위해서",hint:"Formal purpose expression: came to this place with the goal of doing something."},
{type:"fb",s:"어제 {1} 비빔밥이 정말 맛있었어요.\n(The bibimbap I ate yesterday was really delicious.)",a:["먹은"],opts:["먹은","먹는","먹을","먹기"],hint:"Yesterday's bibimbap: use the past tense modifier form of the eating verb."},
{type:"drag_fill",s:"한국 음식을 배우{1} 위해서 요리 학원에 {2} 있어요.\n(I am attending a cooking academy in order to learn Korean food.)",blanks:{"1":"기","2":"다니고"},pool:["기","다니고","는","다녀서","게","다니면"],hint:"-기 위해서 (purpose) + -고 있다 (progressive)."},
{type:"match",pairs:[{trg:"요리하다",src:"to cook"},{trg:"굽다",src:"to grill, to roast"},{trg:"볶다",src:"to stir-fry"},{trg:"시키다",src:"to order (food/delivery)"},{trg:"레시피",src:"recipe"},{trg:"남다",src:"to remain, to be left over"}]},{type:"match",pairs:[{trg:"주문하다",src:"to order (at a restaurant)"},{trg:"맵다",src:"to be spicy"},{trg:"싱겁다",src:"to be bland"},{trg:"젓가락",src:"chopsticks"}]}]},

// ── L10: TOPIK II 추상 개념 (24 steps) ──
{id:"kov2_u18l_topik2_abstract",title:"TOPIK II 추상 개념",icon:"💡",xp:28,board:true,steps:[
{type:"intro",title:"Abstract Concepts for TOPIK II",desc:"Move beyond concrete nouns.\n\nAt B1 you discuss society, goals, and problems.\nThese words unlock civic and academic topics.",goals:["Learn 9 TOPIK II abstract nouns and verbs","Use abstract vocab in real B1 sentences","Practice with fb and drag_fill production","Combine with -기 위해서 and -는 것"]},

{type:"teach",trg:"기회",src:"opportunity, chance",pos:"noun",gender:null,
note:"Sino-Korean: 기(chance/機) + 회(meeting/會).\n기회를 잡다 = seize an opportunity.\n좋은 기회 = a good chance.",
example:"A: 이번 기회를 놓치면 안 돼요.\nB: 맞아요. 좋은 기회가 자주 오지 않아요.\nA: 그러면 도전해 볼까요?\nB: 네, 기회가 있을 때 도전해야 해요.",
exampleSrc:"A: We must not miss this opportunity.\nB: That is right. Good chances do not come often.\nA: Then shall we try?\nB: Yes, you have to try when you have the chance.",
funFact:"The hanja 機 also appears in 비행기 (airplane). The character suggests a pivotal mechanism or turning point."},

{type:"teach",trg:"결과",src:"result, outcome",pos:"noun",gender:null,
note:"Sino-Korean: 결(decide/結) + 과(fruit/果).\n결과가 좋다 = the result is good.\n결과를 기다리다 = wait for the result.",
example:"A: 시험 결과가 어땠어요?\nB: 결과가 좋았어요! 열심히 공부한 결과예요.\nA: 정말요? 축하해요!\nB: 감사해요. 좋은 결과를 받아서 기분이 좋아요.",
exampleSrc:"A: How was your exam result?\nB: The result was good! It is the result of studying hard.\nA: Really? Congratulations!\nB: Thank you. I feel great getting a good result.",
funFact:"결과 pairs with 원인 (cause): 원인과 결과 = cause and effect, a key phrase in Korean academic writing."},

{type:"teach",trg:"이유",src:"reason, cause",pos:"noun",gender:null,
note:"Sino-Korean: 이(reason/理) + 유(reason/由).\n이유가 있다 = there is a reason.\n이유를 설명하다 = explain a reason.",
example:"A: 왜 한국어를 배워요?\nB: 이유는 간단해요. 한국 문화를 좋아해요.\nA: 좋은 이유네요!\nB: 이유가 있으면 더 열심히 할 수 있어요.",
exampleSrc:"A: Why do you learn Korean?\nB: The reason is simple. I like Korean culture.\nA: That is a good reason!\nB: If you have a reason, you can work harder.",
funFact:"이유 vs 까닭: 이유 is Sino-Korean (formal/neutral), 까닭 is pure Korean (literary). Both mean reason. TOPIK II tests both."},

{type:"teach",trg:"목표",src:"goal, target",pos:"noun",gender:null,
note:"Sino-Korean: 목(eye/目) + 표(mark/標).\n목표를 세우다 = set a goal.\n목표를 이루다 = achieve a goal.",
example:"A: 올해 목표가 뭐예요?\nB: 한국어 시험을 통과하는 것이 목표예요.\nA: 좋은 목표예요! 열심히 하면 이룰 수 있어요.\nB: 목표를 이루기 위해서 매일 공부하고 있어요.",
exampleSrc:"A: What is your goal this year?\nB: Passing the Korean language test is my goal.\nA: That is a great goal! If you work hard you can achieve it.\nB: I am studying every day in order to achieve my goal.",
funFact:"The expression 목표를 향해 나아가다 (move toward a goal) is common in Korean motivational writing and TOPIK essay prompts."},

{type:"teach",trg:"문제",src:"problem, issue",pos:"noun",gender:null,
note:"Sino-Korean: 문(question/問) + 제(topic/題).\n문제가 생기다 = a problem arises.\n문제를 해결하다 = solve a problem.",
example:"A: 무슨 문제가 있어요?\nB: 요즘 건강 문제가 있어요.\nA: 걱정이에요. 도와줄 수 있어요?\nB: 감사해요. 문제를 같이 해결하면 좋겠어요.",
exampleSrc:"A: Is there a problem?\nB: I have a health problem these days.\nA: I am worried. Can I help you?\nB: Thank you. It would be nice to solve the problem together.",
funFact:"문제 also means an exam question (시험 문제). Context makes the meaning clear, which is exactly what TOPIK II tests."},

{type:"teach",trg:"사회",src:"society",pos:"noun",gender:null,
note:"Sino-Korean: 사(group/社) + 회(meeting/會).\n사회 문제 = social issue.\n사회에 참여하다 = participate in society.",
example:"A: 사회에서 중요한 것이 뭐예요?\nB: 서로 돕는 것이 중요하다고 생각해요.\nA: 맞아요. 좋은 사회를 만들기 위해서 노력해야 해요.\nB: 사회 문제에 관심을 가지는 것도 중요해요.",
exampleSrc:"A: What is important in society?\nB: I think helping each other is important.\nA: That is right. We must make efforts to build a good society.\nB: Taking an interest in social issues is also important.",
funFact:"사회 is a TOPIK II high-frequency word that appears in essay prompts about modern life, justice, and community values."},

{type:"teach",trg:"참여하다",src:"to participate, to take part",pos:"verb",gender:null,
note:"Sino-Korean: 참(attend/參) + 여(join/與) + 하다.\n행사에 참여하다 = participate in an event.\n토론에 참여하다 = take part in a debate.",
example:"A: 이번 행사에 참여할 거예요?\nB: 네, 꼭 참여하고 싶어요.\nA: 참여하는 사람이 많을 것 같아요.\nB: 같이 참여하기 위해서 일찍 도착했어요.",
exampleSrc:"A: Will you participate in this event?\nB: Yes, I really want to take part.\nA: I think many people will participate.\nB: I arrived early in order to take part together.",
funFact:"In Korean civic life, 시민 참여 (citizen participation) is a key concept. TOPIK II essays frequently ask about how citizens can contribute to society."},

{type:"teach",trg:"제안하다",src:"to suggest, to propose",pos:"verb",gender:null,
note:"Sino-Korean: 제(present/提) + 안(plan/案) + 하다.\n아이디어를 제안하다 = propose an idea.\n해결책을 제안하다 = suggest a solution.",
example:"A: 문제를 해결할 방법이 있어요?\nB: 제가 한 가지 제안할게요.\nA: 좋아요. 무슨 아이디어예요?\nB: 함께 참여하는 프로그램을 만드는 것을 제안해요.",
exampleSrc:"A: Do you have a way to solve the problem?\nB: I will suggest one thing.\nA: Sure. What is the idea?\nB: I suggest creating a program that everyone participates in together.",
funFact:"제안 (proposal) is distinct from 요청 (request): a 제안 invites discussion, while a 요청 asks for action. TOPIK II writing tests this distinction."},

{type:"teach",trg:"발전하다",src:"to develop, to advance, to progress",pos:"verb",gender:null,
note:"Sino-Korean: 발(rise/發) + 전(unfold/展) + 하다.\n사회가 발전하다 = society progresses.\n빠르게 발전하다 = develop rapidly.",
example:"A: 한국이 많이 발전했네요.\nB: 맞아요. 기술과 사회가 함께 발전했어요.\nA: 앞으로도 계속 발전할 것 같아요.\nB: 좋은 기회를 잘 살리면 더 발전할 수 있어요.",
exampleSrc:"A: Korea has developed a lot.\nB: That is right. Technology and society have advanced together.\nA: It seems it will keep developing in the future too.\nB: If we make good use of opportunities, we can advance further.",
funFact:"발전 also appears in the noun form alone (발전 = development/progress) and in 경제 발전 (economic development), a staple of TOPIK II essays."},

{type:"tip",title:"Abstract Nouns in Korean Civic Discourse",text:"These nouns are the building blocks of B1-B2 Korean.\n\n기회 = opportunity\n결과 = result\n이유 = reason\n목표 = goal\n문제 = problem\n사회 = society\n\nAll six combine naturally:\n사회 문제를 해결하기 위해서...\n= In order to solve social problems...\n\n목표를 이루는 것이 중요해요.\n= Achieving goals is important.",
deepDive:"TOPIK II essay pattern: 이유 + 결과\n\nKorean academic writing uses a predictable structure:\n\n왜냐하면 A이기 때문이다.\n그 결과, B가 생겼다.\n이 문제를 해결하기 위해서 C가 필요하다.\n\nTranslation pattern:\nThe reason is because A.\nAs a result, B occurred.\nIn order to solve this problem, C is needed.\n\nMastering these 6 nouns unlocks essay structure on TOPIK II."},

{type:"mc",q:"기회를 잡다 means:",opts:["to seize an opportunity","to create an opportunity","to discuss an opportunity","to miss an opportunity"],ans:"to seize an opportunity",hint:"잡다 means to grab or catch. What do you do to an … when you act on it?"},

{type:"fb",s:"이번 기회를 {1}으면 안 돼요.\n(We must not miss this opportunity.)",a:"놓치",opts:["놓치","잡","만들","포기"],hint:"놓치다 = to miss, to let slip. Choose the stem that means failing to catch an opportunity."},

{type:"mc",q:"열심히 공부한 결과예요 means:",opts:["It is hard to study for results","It is the result of studying hard","I will study hard for results","Studying hard has no results"],ans:"It is the result of studying hard",hint:"결과 = …/outcome. -ㄴ 결과 = as a … of doing. 공부한 = studied (past modifier)."},

{type:"fb",s:"문제를 해결하{1} 위해서 같이 생각해 봐요.\n(Let us think together in order to solve the problem.)",a:"기",opts:["기","는","는 것","기로"],hint:"-기 위해서 = in order to. Which suffix attaches to the verb stem for formal purpose?"},

{type:"mc",q:"이유를 설명하다 means:",opts:["to make a reason","to look for a reason","to explain a reason","to ignore a reason"],ans:"to explain a reason",hint:"설명하다 = to …. 이유 = …. Which action pairs naturally with giving a …?"},

{type:"fb",s:"사회 {1}에 관심을 가지는 것이 중요해요.\n(Taking an interest in social issues is important.)",a:"문제",opts:["문제","기회","결과","목표"],hint:"The phrase 사회 ___ = social ___. Which noun means issue or problem?"},

{type:"drag_fill",s:"좋은 {1}를 이루{2} 위해서 매일 노력하는 것이 {3}.\n(In order to achieve a good goal, trying every day is important.)",blanks:{"1":"목표","2":"기","3":"중요해요"},pool:["목표","기","중요해요","결과","는","좋아요"],hint:"Goal = 목표. In order to achieve = 이루기 위해서. Is important = 중요해요."},

{type:"fb",s:"이번 행사에 꼭 {1}하고 싶어요.\n(I really want to participate in this event.)",a:"참여",opts:["참여","제안","발전","해결"],hint:"Taking part in an event. Which verb means to participate?"},

{type:"mc",q:"제안하다 vs 요청하다:",opts:["To demand vs to respond","Same meaning","Both mean to refuse","To suggest (open to discussion) vs to request (action expected)"],ans:"To suggest (open to discussion) vs to request (action expected)",hint:"제안하다 invites input. 요청하다 asks for something specific. The nuance matters in formal contexts."},

{type:"fb",s:"사회가 빠르게 {1}하고 있어요.\n(Society is developing rapidly.)",a:"발전",opts:["발전","참여","제안","결과"],hint:"Society is making progress. Which verb means to develop or advance?"},

{type:"drag_fill",s:"문제의 {1}를 알면 더 좋은 해결책을 {2}할 수 있어요.\n(If you know the reason for a problem, you can suggest a better solution.)",blanks:{"1":"이유","2":"제안"},pool:["이유","제안","결과","목표","참여","발전"],hint:"Reason for a problem = 이유. Suggest a solution = 제안하다."},

{type:"mc",q:"사회에 참여하는 것이 중요하다고 생각해요 combines:",opts:["Three: -는 것 + 중요하다 + -다고 (reported opinion)","Only -는 것","Only 중요하다","Only -다고"],ans:"Three: -는 것 + 중요하다 + -다고 (reported opinion)",hint:"참여하는 것 = the act of participating (nominalized). -다고 생각해요 = I think that. Count the grammar layers."},

{type:"fb",s:"그 결과, 사회가 더 {1}했어요.\n(As a result, society advanced further.)",a:"발전",opts:["발전","참여","제안","문제"],hint:"Society made progress or advanced. Which verb describes moving forward in development?"},

{type:"match",pairs:[{trg:"기회",src:"opportunity"},{trg:"결과",src:"result"},{trg:"이유",src:"reason"},{trg:"목표",src:"goal"},{trg:"문제",src:"problem"},{trg:"사회",src:"society"}]},

{type:"match",pairs:[{trg:"참여하다",src:"to participate"},{trg:"제안하다",src:"to suggest"},{trg:"발전하다",src:"to develop, advance"},{trg:"문제를 해결하다",src:"to solve a problem"}]}
]}

]};

